func ProcessItems(ctx context.Context, items []Item) ([]Result, error) {
    numWorkers := runtime.NumCPU()
    jobs := make(chan Item, len(items))    // owned by main, closed by main
    results := make(chan Result, len(items))

    var wg sync.WaitGroup
    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for {
                select {
                case <-ctx.Done():
                    return
                case item, ok := <-jobs:
                    if !ok {
                        return
                    }
                    results <- processItem(ctx, item)
                }
            }
        }()
    }

    for _, item := range items {
        jobs <- item
    }
    close(jobs)  // only writer closes

    go func() {
        wg.Wait()
        close(results)
    }()

    var out []Result
    for r := range results {
        out = append(out, r)
    }
    return out, nil
}
